-- ══════════════════════════════════════════════════════════════════════════════
-- SOP 1: Gamificação — Desenvolvimento de Experiência VR para Lançamentos
-- slug: tbo-gam-007-desenvolvimento-experiencia-vr
-- ══════════════════════════════════════════════════════════════════════════════

  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Desenvolvimento de Experiência VR para Lançamentos Imobiliários',
    'tbo-gam-007-desenvolvimento-experiencia-vr',
    'gamificacao',
    'processo',
    'Processo completo de concepção, produção técnica, integração, testes e entrega de experiências de Realidade Virtual (VR) para lançamentos imobiliários — do briefing ao deploy em estande ou plataforma web',
    E'## Desenvolvimento de Experiência VR para Lançamentos Imobiliários\n\n### 1. Objetivo\nPadronizar o processo de produção de experiências VR (Realidade Virtual) para lançamentos imobiliários da TBO, garantindo qualidade técnica, fidelidade ao projeto arquitetônico, performance nos dispositivos alvo e entrega dentro do prazo. O processo cobre desde o briefing técnico até a instalação e suporte no dia do lançamento.\n\n### 2. Escopo\n**Quem executa:** Equipe de Gamificação + colaboração de Digital 3D (assets)\n**Quando se aplica:** Sempre que um cliente contrata experiência VR como parte do pacote de lançamento\n**Plataformas cobertas:** Oculus Quest 2/3, Meta Quest Pro, HTC Vive, WebXR (browser-based)\n**Exclusões:** AR (Realidade Aumentada) — coberto pelo SOP tbo-gam-006; configuradores 3D web — coberto pelo SOP tbo-gam-003\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Briefing técnico VR | Líder Gamificação | Marco (Dir. Criativo) | Atendimento | Ruy |\n| Definição de fluxo e cenas | Líder Gamificação | Marco | Arquiteto/Cliente | Atendimento |\n| Modelagem 3D dos ambientes | Equipe D3D | Líder D3D | Líder Gamificação | — |\n| Otimização de assets para VR | Equipe Gamificação | Líder Gamificação | — | — |\n| Desenvolvimento no engine (Unreal/Unity) | Dev VR | Líder Gamificação | — | — |\n| QA e testes de performance | QA / Líder Gamificação | Marco | — | Atendimento |\n| Aprovação do cliente | Atendimento | Cliente | Líder Gamificação | Marco |\n| Deploy e suporte no evento | Equipe Gamificação | Líder Gamificação | Atendimento | — |\n\n### 4. Pré-requisitos\n- Briefing criativo do empreendimento aprovado (paleta, materialidade, atmosfera)\n- Plantas baixas e cortes aprovados pelo arquiteto (formato DWG ou PDF vetorial)\n- Modelos 3D do projeto concluídos pelo time D3D ou fornecidos pelo cliente\n- Definição do hardware alvo (quais headsets serão usados no evento)\n- Cronograma de entrega alinhado com data do lançamento (mínimo 6 semanas antes)\n- Acesso ao Google Drive do projeto com todos os assets de referência\n\n### 5. Procedimento\n\n**5.1 Briefing técnico e definição de escopo (Semana 1)**\n1. Reunião de kick-off com Atendimento + cliente: definir cenas, ambientes e interações\n2. Preencher Ficha Técnica VR (ver Template Anexo):\n   - Número de cenas/ambientes (típico: lobby, apartamento tipo, área de lazer, fachada)\n   - Interações esperadas: teleporte livre, teleporte por pontos, zoom, troca de revestimentos, dia/noite\n   - Plataforma alvo: Quest standalone, PCVR ou WebXR\n   - Headsets disponíveis no evento: quantidade, modelo\n   - Operador ou autoatendimento (com ou sem guia)\n3. Validar prazo de entrega com o cronograma master do projeto\n4. Confirmar pacote de assets D3D disponíveis e gap de modelagem adicional\n5. Criar ticket no TBO OS com escopo, prazo e responsáveis\n\n**5.2 Preparação e otimização de assets 3D (Semanas 1-2)**\n1. Receber modelos 3D do time D3D (formato FBX ou OBJ)\n2. Auditoria de polígonos — limite recomendado por cena VR:\n   - Quest standalone: máx. 500k polígonos totais\n   - PCVR: máx. 2M polígonos totais\n3. Retopologia de modelos high-poly para low-poly (se necessário)\n4. Criar UV maps otimizados para bake de iluminação\n5. Produzir texturas PBR (albedo, roughness, metallic, normal map) em 2K/4K\n6. Fazer bake de lightmap para iluminação estática (evitar cálculo em tempo real)\n7. Exportar assets otimizados com nomenclatura: [slug]_[ambiente]_[elemento]_LOD[0-2]\n\n**5.3 Desenvolvimento no engine (Semanas 2-4)**\n1. Criar projeto no Unreal Engine 5 ou Unity (conforme definição do time)\n2. Importar assets otimizados e configurar materiais PBR\n3. Implementar sistema de teleporte:\n   - Teleporte por pontos de interesse (padrão para Quest autoatendimento)\n   - Teleporte livre em área delimitada (para ambientes grandes)\n4. Configurar iluminação (usar baked lighting para performance em Quest)\n5. Implementar interações definidas no briefing:\n   - Troca de revestimentos (materiais swap em tempo real)\n   - Abertura de portas e janelas (animações)\n   - Ciclo dia/noite (se solicitado)\n   - Hotspots informativos (área, especificações)\n6. Criar menu de navegação com mapa do empreendimento como ponto de partida\n7. Implementar sistema de reset automático (após 5 min de inatividade, retornar ao menu)\n8. Configurar audio espacial: música ambiente + narração (se solicitado)\n\n**5.4 QA interno e ajustes (Semana 4-5)**\n1. Executar checklist completo de QA (ver SOP tbo-gam-008)\n2. Medir framerate em hardware alvo:\n   - Meta Quest 2/3: mínimo 72fps constante (ideal: 90fps)\n   - PCVR: mínimo 90fps constante\n3. Testar todas as interações definidas no briefing\n4. Verificar consistência visual com os renders aprovados\n5. Testar ciclo completo de usuario: ligar headset → entrar na experiência → navegar → sair\n6. Corrigir issues e retestar (máx. 2 ciclos de correção)\n\n**5.5 Aprovação do cliente (Semana 5)**\n1. Apresentar demo ao cliente: sessão presencial ou via link WebXR\n2. Coletar feedback estruturado (usar formulário de aprovação — ver Template Anexo)\n3. Categorizar feedback em: crítico (bloqueia aprovação), importante (implementar), cosmético (nice-to-have)\n4. Implementar itens críticos e importantes em até 3 dias úteis\n5. Segunda aprovação: foco nos itens alterados\n6. Obter assinatura de aprovação formal (e-mail ou documento)\n\n**5.6 Build final e preparação para evento (Semana 6)**\n1. Gerar build de produção (sem modo debug, sem logs)\n2. Para Quest standalone: compilar APK via Oculus Developer Hub\n3. Para PCVR: empacotar executável com todas as dependências\n4. Para WebXR: deploy em servidor HTTPS (requerido para WebXR)\n5. Instalar e testar nos headsets que serão usados no evento\n6. Preparar guia de operação para a equipe de estande (ver Template Anexo)\n7. Preparar kit de contingência: backup em HD externo, segundo headset calibrado\n\n**5.7 Suporte no evento**\n1. Chegar no estande 2h antes da abertura para setup e testes\n2. Calibrar todos os headsets (IPD, altura de chão, limites de guarda)\n3. Briefing rápido com a equipe de vendas sobre como operar a experiência\n4. Manter presença técnica por pelo menos as 2 primeiras horas do evento\n5. Monitorar desempenho: baterias, superaquecimento, crashes\n6. Registrar feedback de visitantes para retrospectiva\n\n### 6. Checklist de Validação\n- [ ] Ficha Técnica VR preenchida e aprovada pelo cliente na Semana 1\n- [ ] Assets D3D recebidos e auditados (polígonos dentro do limite)\n- [ ] Framerate ≥ 72fps em hardware alvo (medido no Quest físico, não emulador)\n- [ ] 100% das interações do briefing implementadas e testadas\n- [ ] Ciclo completo de usuário testado (ligar → navegar → sair)\n- [ ] Aprovação formal do cliente documentada\n- [ ] Build de produção instalado e testado nos headsets do evento\n- [ ] Guia de operação entregue para a equipe de estande\n- [ ] Kit de contingência preparado (backup + headset reserva)\n- [ ] Setup no estande concluído ≥ 1h antes da abertura\n\n### 7. Ferramentas e Recursos\n- **Engine**: Unreal Engine 5 (padrão TBO) ou Unity 2022 LTS\n- **Otimização 3D**: Blender (retopologia), RizomUV (UV mapping)\n- **Bake de iluminação**: GPU Lightmass (Unreal) ou Bakery (Unity)\n- **Build Quest**: Oculus Developer Hub, Android Studio (SDK)\n- **WebXR**: A-Frame, Babylon.js ou Three.js + servidor HTTPS\n- **Performance monitoring**: OVR Metrics Tool (Quest), SteamVR Performance Monitor (PCVR)\n- **Assets**: Google Drive do projeto > Gamificação > VR > [Empreendimento]\n- **Gestão**: TBO OS > Projetos > [Projeto] > Gamificação\n\n### 8. SLAs e Métricas\n- **Kick-off a entrega**: máximo 6 semanas\n- **Framerate mínimo**: 72fps no Quest, 90fps no PCVR (medido com headset físico)\n- **Tempo de carregamento inicial**: ≤ 30 segundos\n- **Ciclos de revisão**: máximo 2 após aprovação interna\n- **Uptime no evento**: 99% (máximo 15 min de downtime em evento de 8h)\n- **Satisfação do cliente**: ≥ 4/5 no formulário de aprovação\n- **Tempo de reset automático**: 5 minutos de inatividade\n\n### 9. Troubleshooting\n\n**Framerate abaixo do mínimo no Quest standalone**\n→ Verificar contagem de polígonos — reduzir LODs mais distantes\n→ Checar número de draw calls: ideal ≤ 200 por frame\n→ Substituir iluminação dinâmica por baked lightmaps\n→ Comprimir texturas para formato ASTC (otimizado para mobile GPU)\n→ Desativar anti-aliasing ou reduzir resolução de renderização (72% é aceitável)\n\n**Experiência trava ou fecha inesperadamente no evento**\n→ Verificar temperatura do headset: se quente, pausar 10 min e reiniciar\n→ Reinstalar APK do backup no HD externo\n→ Ativar modo airplane no headset (evita downloads de update durante o evento)\n→ Se problema persistir: ativar segundo headset do kit de contingência\n\n**Cliente solicita alterações após aprovação formal**\n→ Avaliar complexidade: cosmético (aplicar), funcional (negociar prazo + custo adicional)\n→ Documentar solicitação no TBO OS com data e responsável\n→ Alterações pós-aprovação com impacto na entrega: formalizar em e-mail com novo prazo\n\n**Assets D3D chegam fora do prazo (Semana 2)**\n→ Acionar Líder D3D imediatamente com data máxima de recebimento\n→ Avaliar impacto no cronograma: se ≥ 3 dias de atraso, comunicar Marco + Ruy\n→ Trabalhar em paralelo com placeholders para não paralisar o desenvolvimento\n→ Se atraso comprometer data do evento: decisão estratégica com diretoria\n\n### 10. Template Anexo\n\n**Template: Ficha Técnica VR**\n\n```\nEMPREENDIMENTO: ___________  DATA DO EVENTO: ___________\nRESPONSÁVEL TBO: ___________  CONTATO CLIENTE: ___________\n\nHARDWARE ALVO:\n[ ] Meta Quest 2  [ ] Meta Quest 3  [ ] Meta Quest Pro\n[ ] HTC Vive  [ ] Valve Index  [ ] WebXR (browser)\nQtd de headsets no evento: ___\n\nAMBIENTES/CENAS:\n[ ] Fachada/Vista externa  [ ] Lobby/Hall de entrada\n[ ] Apartamento tipo ___m²  [ ] Cobertura ___m²\n[ ] Área de lazer  [ ] Rooftop  [ ] Outro: ___________\n\nINTERAÇÕES:\n[ ] Teleporte por pontos  [ ] Teleporte livre\n[ ] Troca de revestimentos  [ ] Abertura de portas/janelas\n[ ] Ciclo dia/noite  [ ] Hotspots informativos\n[ ] Narração de áudio  [ ] Música ambiente\n[ ] Outro: ___________\n\nMODO DE OPERAÇÃO:\n[ ] Autoatendimento (visitante opera sozinho)\n[ ] Assistido (operador TBO acompanha)\n[ ] Demonstração guiada (vendedor narra)\n\nASSETS DISPONÍVEIS:\n[ ] Modelo 3D completo (FBX/OBJ)  [ ] Apenas plantas (DWG)\n[ ] Renders de referência  [ ] Manual de identidade visual\n[ ] Paleta de cores e materiais\n\nPRAZO MÁXIMO DE ENTREGA: ___________\nDATA DO EVENTO: ___________\n\nOBSERVAÇÕES ESPECIAIS:\n___________\n```\n\n**Template: Guia de Operação para Equipe de Estande**\n\n```\nEXPERIÊNCIA VR — [EMPREENDIMENTO]\nVERSÃO: ___  DATA: ___  CONTATO TÉCNICO TBO: ___ (WhatsApp: ___)\n\nLIGAR O HEADSET:\n1. Pressionar botão lateral por 3 segundos\n2. Aguardar tela de boas-vindas (aprox. 30 segundos)\n3. Abrir app "[Nome do empreendimento]" na tela inicial\n\nCOLOCAR NO VISITANTE:\n1. Ajustar IPD (distância entre lentes) para o visitante\n2. Ajustar alça para que headset fique firme mas confortável\n3. Verificar se a imagem está nítida (pedir ao visitante)\n4. Entregar controles e mostrar como segurar\n\nDURACÃO RECOMENDADA: 5-8 minutos por visitante\n\nREINICIAR PARA PRÓXIMO VISITANTE:\n1. Pressionar botão "Home" no controle\n2. Selecionar "Reiniciar experiência" no menu\n3. Aguardar 10 segundos para o próximo visitante\n\nPROBLEMAS COMUNS:\n- Imagem borrada: ajustar IPD ou posição do headset\n- Experiência travada: pressionar botão lateral por 5s para reiniciar\n- Bateria baixa (< 20%): conectar carregador e usar headset reserva\n- Qualquer outro problema: ligar para [contato TBO]\n```',
    '<h2>Desenvolvimento de Experiência VR para Lançamentos Imobiliários</h2><p>Processo completo de concepção, produção e entrega de experiências VR para lançamentos imobiliários — do briefing técnico ao suporte no dia do evento.</p>',
    'published',
    'high',
    ARRAY['gamificacao', 'vr', 'realidade-virtual', 'unreal-engine', 'unity', 'oculus', 'quest', 'lancamento', 'imobiliario', 'producao', '3d']::TEXT[],
    0,
    1
  ) ON CONFLICT (tenant_id, slug) DO UPDATE SET
    title = EXCLUDED.title,
    content = EXCLUDED.content,
    status = EXCLUDED.status,
    updated_at = NOW();

  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-gam-007-desenvolvimento-experiencia-vr';

  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index)
  SELECT v_sop_id, s.step_number, s.title, s.content, s.step_type, s.order_index
  FROM (VALUES
    (1, 'Objetivo', 'Padronizar o processo de produção de experiências VR para lançamentos imobiliários da TBO, garantindo qualidade técnica, fidelidade ao projeto arquitetônico, performance nos dispositivos alvo e entrega dentro do prazo. O processo cobre desde o briefing técnico até a instalação e suporte no dia do lançamento.', 'step', 0),
    (2, 'Escopo', E'**Quem executa:** Equipe de Gamificação + colaboração de Digital 3D (assets)\n**Quando se aplica:** Sempre que um cliente contrata experiência VR como parte do pacote de lançamento\n**Plataformas cobertas:** Oculus Quest 2/3, Meta Quest Pro, HTC Vive, WebXR\n**Exclusões:** AR (tbo-gam-006), configuradores 3D web (tbo-gam-003)', 'step', 1),
    (3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Briefing técnico VR | Líder Gamificação | Marco | Atendimento | Ruy |\n| Modelagem 3D dos ambientes | Equipe D3D | Líder D3D | Líder Gamificação | — |\n| Otimização de assets para VR | Equipe Gamificação | Líder Gamificação | — | — |\n| Desenvolvimento no engine | Dev VR | Líder Gamificação | — | — |\n| QA e testes | QA / Líder Gamificação | Marco | — | Atendimento |\n| Aprovação do cliente | Atendimento | Cliente | Líder Gamificação | Marco |\n| Deploy e suporte no evento | Equipe Gamificação | Líder Gamificação | Atendimento | — |', 'step', 2),
    (4, 'Pré-requisitos', E'- Briefing criativo do empreendimento aprovado (paleta, materialidade, atmosfera)\n- Plantas baixas e cortes aprovados pelo arquiteto (formato DWG ou PDF vetorial)\n- Modelos 3D do projeto concluídos pelo time D3D ou fornecidos pelo cliente\n- Definição do hardware alvo (quais headsets serão usados no evento)\n- Cronograma de entrega alinhado com data do lançamento (mínimo 6 semanas antes)\n- Acesso ao Google Drive do projeto com todos os assets de referência', 'step', 3),
    (5, 'Procedimento', E'**Semana 1 — Briefing técnico:** Reunião de kick-off, preencher Ficha Técnica VR (cenas, interações, plataforma, qtd headsets). Criar ticket no TBO OS.\n\n**Semanas 1-2 — Preparação de assets:** Receber modelos 3D do D3D, auditar polígonos (Quest: máx. 500k, PCVR: máx. 2M), retopologia se necessário, bake de lightmaps, texturas PBR em 2K/4K.\n\n**Semanas 2-4 — Desenvolvimento:** Importar assets no engine, sistema de teleporte, interações (troca de revestimentos, hotspots, ciclo dia/noite), menu de navegação, reset automático em 5min, audio espacial.\n\n**Semanas 4-5 — QA interno:** Executar checklist de QA, medir framerate no hardware físico (min. 72fps Quest / 90fps PCVR), testar ciclo completo de usuário.\n\n**Semana 5 — Aprovação do cliente:** Demo presencial ou WebXR, formulário de feedback, implementar itens críticos em 3 dias úteis, aprovação formal.\n\n**Semana 6 — Build final e evento:** Build de produção (sem debug), instalar nos headsets do evento, guia de operação para equipe de estande, kit de contingência.', 'step', 4),
    (6, 'Checklist de Validação', E'- [ ] Ficha Técnica VR aprovada na Semana 1\n- [ ] Assets D3D auditados (polígonos dentro do limite)\n- [ ] Framerate ≥ 72fps no Quest físico (não emulador)\n- [ ] 100% das interações do briefing implementadas\n- [ ] Ciclo completo testado (ligar → navegar → sair)\n- [ ] Aprovação formal do cliente documentada\n- [ ] Build instalado nos headsets do evento\n- [ ] Guia de operação entregue para equipe de estande\n- [ ] Kit de contingência preparado (backup + headset reserva)\n- [ ] Setup no estande ≥ 1h antes da abertura', 'checkpoint', 5),
    (7, 'Ferramentas e Recursos', E'- **Engine**: Unreal Engine 5 (padrão) ou Unity 2022 LTS\n- **Otimização 3D**: Blender, RizomUV\n- **Build Quest**: Oculus Developer Hub, Android Studio\n- **WebXR**: A-Frame, Babylon.js + servidor HTTPS\n- **Performance**: OVR Metrics Tool, SteamVR Performance Monitor\n- **Assets**: Google Drive > [Projeto] > Gamificação > VR', 'tip', 6),
    (8, 'SLAs e Métricas', E'- **Kick-off a entrega**: máximo 6 semanas\n- **Framerate mínimo**: 72fps Quest, 90fps PCVR\n- **Carregamento inicial**: ≤ 30 segundos\n- **Ciclos de revisão**: máximo 2 após QA interno\n- **Uptime no evento**: 99% (máx. 15 min downtime em 8h)\n- **Satisfação do cliente**: ≥ 4/5 no formulário de aprovação', 'note', 7),
    (9, 'Troubleshooting', E'**Framerate abaixo do mínimo no Quest:** Reduzir polígonos/LODs, checar draw calls (ideal ≤ 200/frame), substituir iluminação dinâmica por baked, usar textura ASTC, reduzir resolução de renderização para 72%.\n\n**Experiência trava no evento:** Verificar temperatura, reinstalar APK do backup, ativar modo airplane. Se persistir: ativar headset de contingência.\n\n**Cliente solicita alterações pós-aprovação:** Cosmético → aplicar. Funcional → negociar prazo + custo adicional. Documentar no TBO OS.\n\n**Assets D3D chegam com atraso:** Acionar Líder D3D, trabalhar com placeholders, se impacto ≥ 3 dias comunicar Marco + Ruy.', 'warning', 8),
    (10, 'Template Anexo', E'**Ficha Técnica VR** (ver content principal)\n**Guia de Operação para Equipe de Estande** (ver content principal)\n\nAmbos os templates estão no formato copy-paste ready para uso imediato no briefing e no dia do evento.', 'tip', 9)
  ) AS s(step_number, title, content, step_type, order_index)
  ON CONFLICT DO NOTHING;

-- ══════════════════════════════════════════════════════════════════════════════
-- SOP 2: Gamificação — QA e Homologação de Experiências Interativas
-- slug: tbo-gam-008-qa-homologacao-experiencias-interativas
-- ══════════════════════════════════════════════════════════════════════════════

  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'QA e Homologação de Experiências Interativas',
    'tbo-gam-008-qa-homologacao-experiencias-interativas',
    'gamificacao',
    'checklist',
    'Processo de garantia de qualidade (QA) e homologação para todas as experiências interativas produzidas pela TBO — configuradores 3D, tours virtuais, realidade aumentada, VR e mapas interativos — antes da entrega ao cliente',
    E'## QA e Homologação de Experiências Interativas\n\n### 1. Objetivo\nGarantir que toda experiência interativa entregue pela TBO passe por um processo estruturado de testes e homologação antes de chegar ao cliente, eliminando bugs críticos, validando performance, consistência visual e funcionalidades prometidas no briefing. O QA protege a reputação da TBO e evita retrabalho emergencial em datas de lançamento.\n\n### 2. Escopo\n**Quem executa:** Líder de Gamificação + Dev responsável pela experiência\n**Quando se aplica:** Obrigatório em TODA entrega de experiência interativa, sem exceções\n**Experiências cobertas:** Configuradores 3D web, tours virtuais 360°, experiências VR, AR mobile, mapas interativos de implantação\n**Exclusões:** Renders estáticos e imagens (cobertos pelo QA de D3D)\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Plano de testes | Líder Gamificação | Marco | Dev responsável | — |\n| Execução dos testes | Dev responsável | Líder Gamificação | — | — |\n| Registro de bugs | Dev responsável | Líder Gamificação | — | — |\n| Correção de bugs críticos | Dev responsável | Líder Gamificação | — | Atendimento |\n| Aprovação interna de QA | Líder Gamificação | Marco | — | Atendimento |\n| Demo para aprovação do cliente | Atendimento | Cliente | Líder Gamificação | Marco |\n| Homologação final | Líder Gamificação | Marco | — | Ruy |\n\n### 4. Pré-requisitos\n- Build de staging ou ambiente de homologação disponível (NUNCA testar em produção)\n- Checklist de funcionalidades do briefing documentado\n- Dispositivos de teste disponíveis (desktop, mobile, headset VR — conforme o tipo de experiência)\n- Acesso ao documento de briefing aprovado com todas as funcionalidades listadas\n- Ticket de QA criado no TBO OS com prazo e responsável\n\n### 5. Procedimento\n\n**5.1 Preparação do plano de testes**\n1. Listar todas as funcionalidades do briefing aprovado\n2. Criar matriz de testes no TBO OS: funcionalidade × dispositivo × status (pass/fail/blocker)\n3. Definir criticidade de cada funcionalidade: crítica (bloqueia entrega), importante (deve funcionar), cosmética (nice-to-have)\n4. Preparar ambiente de teste com dados reais (não mocks)\n\n**5.2 Testes de funcionalidade**\n1. Testar CADA funcionalidade listada no briefing — marcar pass/fail\n2. Para configuradores 3D:\n   - Troca de todos os materiais/acabamentos: verificar se aplica corretamente\n   - Cálculo de preço (se houver): verificar fórmula e formatação\n   - Compartilhamento: gerar link e testar em dispositivo diferente\n   - Exportar/salvar configuração: verificar arquivo gerado\n3. Para tours virtuais 360°:\n   - Navegação entre todos os ambientes\n   - Hotspots informativos: título, descrição, imagem (se houver)\n   - Controles: mouse, touch, VR controller, teclado\n   - Carregamento em conexão lenta (simular 3G/4G)\n4. Para VR:\n   - Executar checklist completo do SOP tbo-gam-007\n   - Medir framerate em hardware físico\n   - Testar autonomia de bateria (mínimo 2h contínuas)\n5. Para AR mobile:\n   - Testar em iOS e Android (modelos diferentes)\n   - Reconhecimento de superfícies: piso, mesa, outdoor\n   - Estabilidade da âncora (objeto não deve "flutuar")\n   - Iluminação adaptativa (sombras realistas)\n\n**5.3 Testes de performance**\n1. **Web (configurador/tour):**\n   - Tempo de carregamento inicial: ≤ 5s em 50Mbps\n   - FPS estável: ≥ 30fps em desktop mid-range, ≥ 24fps em mobile\n   - Uso de memória: sem vazamentos (verificar após 15 min de uso contínuo)\n   - Testar nos browsers: Chrome, Safari, Firefox, Edge\n2. **Mobile (AR):**\n   - Sem aquecimento excessivo após 10 min de uso\n   - Sem crashes em iOS 16+ e Android 10+\n3. **VR:**\n   - Framerate mínimo: 72fps Quest, 90fps PCVR (usar ferramentas de profiling)\n   - Thermal throttling: testar 30 min contínuos sem queda de performance\n\n**5.4 Testes de consistência visual**\n1. Comparar cada ambiente/cena com o render de referência aprovado\n2. Verificar: cores, materiais, iluminação, escala de mobiliário\n3. Verificar tipografia e elementos de UI conforme identidade visual\n4. Testar em diferentes configurações de tela: 1080p, 1440p, 4K, mobile retina\n5. Verificar modo escuro/claro (se aplicável)\n\n**5.5 Testes de usabilidade**\n1. Pedido de opinião a pessoa que não participou do desenvolvimento (internal user test)\n2. Verificar: intuitivo sem manual? Ações respondem em < 100ms? Feedback visual claro?\n3. Testar com usuário leigo em tecnologia (simular perfil do visitante de estande)\n4. Verificar acessibilidade básica: contraste de cores, tamanho de texto, área de toque (mobile ≥ 44px)\n\n**5.6 Classificação e priorização de bugs**\n1. Registrar TODOS os issues encontrados no TBO OS com:\n   - Descrição: o que acontece\n   - Passos para reproduzir\n   - Screenshot/vídeo\n   - Dispositivo/browser afetado\n   - Criticidade: P0 (bloqueia entrega) | P1 (importante) | P2 (cosmético)\n2. Priorização:\n   - **P0 (Blocker)**: bugs críticos que quebram a experiência ou funcionalidade do briefing — corrigir antes de qualquer entrega\n   - **P1 (Major)**: problemas importantes mas com workaround — corrigir antes da entrega\n   - **P2 (Minor)**: cosméticos sem impacto funcional — corrigir se houver tempo, documentar se não houver\n\n**5.7 Ciclos de correção e reteste**\n1. Dev corrige todos os P0 e P1\n2. QA retesta especificamente os issues corrigidos + regressão rápida\n3. Máximo 2 ciclos de correção/reteste antes da aprovação interna\n4. Se houver P0 após 2 ciclos: escalar para Líder Gamificação + Marco\n\n**5.8 Aprovação interna e liberação para cliente**\n1. Líder de Gamificação revisa o relatório de QA\n2. Confirmar: zero P0s abertos, P1s resolvidos ou documentados com justificativa\n3. Registrar aprovação no TBO OS com data e responsável\n4. Passar para Atendimento coordenar demo com o cliente\n\n### 6. Checklist de Validação\n- [ ] Plano de testes criado com todas as funcionalidades do briefing\n- [ ] 100% das funcionalidades críticas testadas e aprovadas (pass)\n- [ ] Zero bugs P0 abertos na entrega\n- [ ] Performance testada nos dispositivos alvo (não apenas emulador)\n- [ ] Consistência visual comparada com renders de referência\n- [ ] Teste de usabilidade com usuário não-técnico realizado\n- [ ] Todos os bugs registrados no TBO OS com criticidade\n- [ ] Aprovação interna registrada com data no TBO OS\n- [ ] Atendimento notificado para coordenar demo com cliente\n\n### 7. Ferramentas e Recursos\n- **Gestão de bugs**: TBO OS > Projetos > [Projeto] > QA\n- **Performance web**: Chrome DevTools (Lighthouse), WebPageTest\n- **Performance VR**: OVR Metrics Tool, SteamVR Performance Monitor, Unity Profiler\n- **Performance mobile**: Android Profiler, Xcode Instruments\n- **Gravação de tela**: Loom (para evidências de bugs)\n- **Browsers para testar**: Chrome, Safari, Firefox, Edge (todos em versão atual)\n- **Dispositivos mobile**: iPhone (iOS atual) + Android (Samsung ou similar)\n\n### 8. SLAs e Métricas\n- **Duração do QA**: mínimo 1 dia para experiência simples, 3 dias para VR complexo\n- **Zero P0 bugs**: obrigatório antes de qualquer entrega ao cliente\n- **Tempo de resolução P0**: ≤ 24h após identificação\n- **Tempo de resolução P1**: ≤ 48h após identificação\n- **Ciclos máximos**: 2 ciclos de QA antes de escalar\n- **Cobertura de funcionalidades**: 100% das funcionalidades do briefing testadas\n\n### 9. Troubleshooting\n\n**Bug P0 encontrado muito próximo da data de entrega**\n→ Comunicar imediatamente Líder Gamificação + Atendimento\n→ Avaliar: é possível corrigir sem comprometer prazo?\n→ Se não: avaliar entrega parcial (desabilitar feature problemática) com comunicação ao cliente\n→ Documentar decisão e aprovação da diretoria no TBO OS\n\n**Performance abaixo do esperado só em dispositivo específico**\n→ Verificar se é um bug do device/OS ou do código\n→ Documentar como P1 com device e OS version\n→ Avaliar se o dispositivo é representativo do público-alvo\n→ Se for device do cliente no evento: priorizar como P0\n\n**Cliente testa durante QA (antes da aprovação interna)**\n→ Informar gentilmente que a experiência ainda está em QA\n→ Não compartilhar links de staging sem aviso sobre estado\n→ Usar subdomínio staging.tbo.com.br com mensagem clara de "versão em testes"\n\n### 10. Template Anexo\n\n**Template: Matriz de QA**\n\n```\nEXPERIÊNCIA: ___________  VERSÃO: ___  DATA: ___\nTESTADO POR: ___________  DEVICES USADOS: ___________\n\n## FUNCIONALIDADES (do briefing)\n\n| ID | Funcionalidade | Criticidade | Chrome | Safari | Mobile | VR | Status | Bug ID |\n|----|----------------|-------------|--------|--------|--------|----|--------|--------|\n| F01 | Trocar revestimento piso | Crítica | ✅ | ✅ | ✅ | — | PASS | — |\n| F02 | Calcular preço | Crítica | ✅ | ✅ | ✅ | — | PASS | — |\n| F03 | Compartilhar via link | Importante | ✅ | ❌ | — | — | FAIL | BUG-003 |\n| F04 | Exportar PDF | Cosmética | ✅ | ✅ | ✅ | — | PASS | — |\n\n## PERFORMANCE\n\n| Métrica | Target | Resultado | Status |\n|---------|--------|-----------|--------|\n| Carregamento inicial | ≤ 5s | 3.2s | ✅ PASS |\n| FPS desktop | ≥ 30fps | 58fps | ✅ PASS |\n| FPS mobile | ≥ 24fps | 28fps | ✅ PASS |\n| Framerate VR | ≥ 72fps | 75fps | ✅ PASS |\n\n## BUGS REGISTRADOS\n\n| ID | Descrição | Criticidade | Device/Browser | Status |\n|----|-----------|-------------|----------------|--------|\n| BUG-003 | Compartilhamento falha no Safari iOS | P1 | iPhone 14 / Safari 17 | Em correção |\n\n## RESULTADO GERAL\n[ ] APROVADO — zero P0, P1s resolvidos → liberar para cliente\n[ ] REPROVADO — P0s abertos → retornar para correção\n[ ] APROVADO COM PENDÊNCIAS — P1s documentados, prazo de correção: ___\n\nAssinatura QA: ___________  Data: ___________\n```',
    '<h2>QA e Homologação de Experiências Interativas</h2><p>Processo de garantia de qualidade obrigatório para todas as experiências interativas da TBO antes de qualquer entrega ao cliente.</p>',
    'published',
    'critical',
    ARRAY['gamificacao', 'qa', 'qualidade', 'testes', 'homologacao', 'bugs', 'performance', 'vr', 'ar', 'configurador', 'tour-virtual']::TEXT[],
    0,
    1
  ) ON CONFLICT (tenant_id, slug) DO UPDATE SET
    title = EXCLUDED.title,
    content = EXCLUDED.content,
    status = EXCLUDED.status,
    updated_at = NOW();

  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-gam-008-qa-homologacao-experiencias-interativas';

  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index)
  SELECT v_sop_id, s.step_number, s.title, s.content, s.step_type, s.order_index
  FROM (VALUES
    (1, 'Objetivo', 'Garantir que toda experiência interativa da TBO passe por testes estruturados antes de chegar ao cliente, eliminando bugs críticos, validando performance e funcionalidades prometidas no briefing. O QA protege a reputação da TBO e evita retrabalho emergencial em datas de lançamento.', 'step', 0),
    (2, 'Escopo', E'**Quem executa:** Líder de Gamificação + Dev responsável\n**Quando se aplica:** OBRIGATÓRIO em toda entrega de experiência interativa, sem exceções\n**Experiências cobertas:** Configuradores 3D web, tours virtuais 360°, VR, AR mobile, mapas interativos\n**Exclusões:** Renders estáticos (cobertos pelo QA de D3D)', 'step', 1),
    (3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Plano de testes | Líder Gamificação | Marco | Dev | — |\n| Execução dos testes | Dev responsável | Líder Gamificação | — | — |\n| Correção de bugs P0 | Dev responsável | Líder Gamificação | — | Atendimento |\n| Aprovação interna de QA | Líder Gamificação | Marco | — | Atendimento |\n| Homologação final | Líder Gamificação | Marco | — | Ruy |', 'step', 2),
    (4, 'Pré-requisitos', E'- Build de staging disponível (NUNCA testar em produção)\n- Checklist de funcionalidades do briefing documentado\n- Dispositivos de teste disponíveis (desktop, mobile, headset VR)\n- Ticket de QA criado no TBO OS com prazo e responsável', 'step', 3),
    (5, 'Procedimento', E'**1. Preparação:** Listar funcionalidades do briefing, criar matriz de testes (funcionalidade × dispositivo × status), definir criticidade (crítica/importante/cosmética).\n\n**2. Testes de funcionalidade:** Testar cada funcionalidade. Para configuradores: todos os materiais, cálculo de preço, compartilhamento, export. Para tours: navegação, hotspots, controles, carregamento em 3G/4G. Para VR: checklist tbo-gam-007 + framerate. Para AR: iOS + Android, reconhecimento de superfície, estabilidade.\n\n**3. Testes de performance:** Web: ≤ 5s carregamento, ≥ 30fps desktop, Chrome/Safari/Firefox/Edge. Mobile: sem aquecimento em 10min. VR: 72fps Quest, 90fps PCVR.\n\n**4. Consistência visual:** Comparar com renders de referência — cores, materiais, escala, tipografia, UI.\n\n**5. Usabilidade:** Teste com usuário não-técnico, verificar resposta ≤ 100ms, acessibilidade básica.\n\n**6. Classificação de bugs:** P0 (bloqueia entrega), P1 (importante), P2 (cosmético). Registrar no TBO OS com screenshot/vídeo.\n\n**7. Correção e reteste:** Máx. 2 ciclos. Se P0 após 2 ciclos: escalar para Marco.\n\n**8. Aprovação:** Zero P0s → registrar aprovação no TBO OS → Atendimento coordena demo com cliente.', 'step', 4),
    (6, 'Checklist de Validação', E'- [ ] Plano de testes criado com funcionalidades do briefing\n- [ ] 100% das funcionalidades críticas aprovadas (pass)\n- [ ] Zero bugs P0 abertos\n- [ ] Performance testada nos dispositivos alvo físicos\n- [ ] Consistência visual verificada com renders de referência\n- [ ] Teste de usabilidade com usuário não-técnico\n- [ ] Todos os bugs registrados no TBO OS\n- [ ] Aprovação interna registrada com data\n- [ ] Atendimento notificado para demo com cliente', 'checkpoint', 5),
    (7, 'Ferramentas e Recursos', E'- **Bugs**: TBO OS > Projetos > [Projeto] > QA\n- **Performance web**: Chrome DevTools Lighthouse\n- **Performance VR**: OVR Metrics Tool, Unity Profiler\n- **Performance mobile**: Android Profiler, Xcode Instruments\n- **Evidências**: Loom (gravação de tela)', 'tip', 6),
    (8, 'SLAs e Métricas', E'- **Duração mínima do QA**: 1 dia (simples), 3 dias (VR complexo)\n- **Zero P0 bugs**: obrigatório antes de qualquer entrega\n- **Resolução P0**: ≤ 24h | **Resolução P1**: ≤ 48h\n- **Ciclos máximos**: 2 antes de escalar\n- **Cobertura**: 100% das funcionalidades do briefing testadas', 'note', 7),
    (9, 'Troubleshooting', E'**P0 próximo da data de entrega:** Comunicar imediatamente Líder + Atendimento. Avaliar entrega parcial (desabilitar feature) com aprovação da diretoria.\n\n**Performance ruim só em device específico:** Documentar como P1. Se for device do evento: priorizar como P0.\n\n**Cliente testa durante QA:** Usar subdomínio staging com aviso claro de "versão em testes". Nunca compartilhar link de staging sem aviso.', 'warning', 8),
    (10, 'Template Anexo', 'Template de Matriz de QA disponível no content principal — inclui tabelas de funcionalidades, performance e bugs em formato copy-paste ready. Usar em TODA execução de QA.', 'tip', 9)
  ) AS s(step_number, title, content, step_type, order_index)
  ON CONFLICT DO NOTHING;

-- ══════════════════════════════════════════════════════════════════════════════
-- SOP 3: Financeiro — Controle de Centro de Custo por BU
-- slug: tbo-fin-008-controle-centro-custo-por-bu
-- ══════════════════════════════════════════════════════════════════════════════

  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Controle de Centro de Custo por BU',
    'tbo-fin-008-controle-centro-custo-por-bu',
    'financeiro',
    'processo',
    'Processo de alocação, rastreamento e controle de custos e receitas por Business Unit (BU) da TBO — BRD, D3D, MKT, AV, INT, ADM, CORP — para garantir visibilidade de margem por unidade e subsidiar decisões estratégicas de pricing e alocação de recursos',
    E'## Controle de Centro de Custo por BU\n\n### 1. Objetivo\nGarantir visibilidade financeira por Business Unit (BU) da TBO, permitindo que a diretoria tome decisões baseadas em dados reais de margem, rentabilidade e eficiência de cada área. O controle de CC (Centro de Custo) é a base para precificação correta, identificação de BUs deficitárias e alocação inteligente de investimentos.\n\n### 2. Escopo\n**Quem executa:** Líder Financeiro + Ruy (validação estratégica)\n**Quando se aplica:** Mensalmente, com fechamento no dia 15 de cada mês (ciclo 15-15)\n**BUs cobertas:**\n- **BRD** — Branding (Celso, Nelson)\n- **D3D** — Digital 3D (Eduarda, Mariane, Lucio)\n- **MKT** — Marketing (Lucca, Rafa, Gustavo, M&N)\n- **AV** — Audiovisual\n- **INT** — Interiores\n- **ADM** — Administrativo\n- **CORP** — Corporativo (Marco, Ruy)\n\n**Exclusões:** DRE consolidada da empresa — coberta pelo SOP tbo-fin-007; conciliação bancária — coberta pelo SOP tbo-fin-004\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Cadastro de CC no OMIE | Líder Financeiro | Ruy | — | Marco |\n| Tagueamento de despesas por CC | Líder Financeiro | Ruy | Líderes de BU | — |\n| Tagueamento de receitas por CC | Líder Financeiro | Ruy | Atendimento/Comercial | — |\n| Reconciliação mensal por BU | Líder Financeiro | Ruy | Líderes de BU | Marco |\n| Análise de margem por BU | Ruy | Marco | Líder Financeiro | — |\n| Report de CC para diretoria | Líder Financeiro | Ruy | — | Marco |\n| Ajuste de alocação de custos | Ruy | Marco | Líder Financeiro | Líderes de BU |\n\n### 4. Pré-requisitos\n- CCs cadastrados no OMIE com nomenclatura padronizada (BRD, D3D, MKT, AV, INT, ADM, CORP)\n- Acesso ao OMIE para Líder Financeiro com permissão de lançamento e relatórios\n- Planilha de CC do mês anterior fechada como baseline\n- Lista de projetos ativos por BU (do TBO OS) para alocação correta de receitas\n- Folha de pagamento do mês fechada com equipe alocada por BU\n\n### 5. Procedimento\n\n**5.1 Estrutura de centros de custo no OMIE**\nCada BU tem um CC fixo. Custos e receitas são lançados com o CC correspondente:\n- Despesas de pessoal: salários, benefícios, treinamentos → CC da BU do colaborador\n- Despesas operacionais: softwares, equipamentos, freelancers → CC da BU que usa\n- Despesas compartilhadas (aluguel, internet, utilities): rateio proporcional por headcount entre CCs (ADM absorve o que não tem BU clara)\n- Receitas de projeto: sempre alocadas à BU principal que executou (ou rateio se multi-BU)\n\n**5.2 Tagueamento de despesas durante o mês (contínuo)**\n1. A cada lançamento de nota fiscal/despesa no OMIE, verificar a qual BU pertence\n2. Selecionar o CC correspondente no campo "Centro de Custo" do OMIE\n3. Para despesas multi-BU (ex: software usado por D3D e MKT): rateio 50/50 no lançamento\n4. Para despesas sem BU clara: alocar no CC ADM com observação descritiva\n5. Freelancers: sempre alocar no CC da BU que contratou e que usará a entrega\n\n**5.3 Tagueamento de receitas durante o mês (contínuo)**\n1. A cada fatura emitida, identificar quais BUs executaram o projeto\n2. Se projeto de BU única: 100% da receita no CC da BU\n3. Se projeto multi-BU (ex: branding + D3D): rateio conforme proposta comercial aprovada\n   - Usar percentuais definidos na proposta (ex: 60% BRD, 40% D3D)\n   - Se não definido na proposta: rateio por horas estimadas de cada BU\n4. Lançar rateio no OMIE com observação: "[Projeto] — rateio conforme proposta dd/mm/aaaa"\n\n**5.4 Fechamento mensal por BU (dia 12-15 do mês)**\n1. Extrair relatório de CC do OMIE: Relatórios > DRE por Centro de Custo > período [dia 15 mês anterior] a [dia 14 mês atual]\n2. Verificar se todas as despesas do mês estão tagueadas com CC\n3. Verificar se todas as receitas do mês estão alocadas com CC\n4. Calcular para cada BU:\n   - **Receita Bruta**: total de faturamento alocado ao CC\n   - **Custos Diretos**: pessoal + freelancers + softwares da BU\n   - **Custos Indiretos**: rateio de despesas compartilhadas (ADM)\n   - **Margem Bruta**: Receita Bruta − Custos Diretos\n   - **Margem Líquida**: Receita Bruta − Custos Diretos − Custos Indiretos\n5. Preencher template de Painel de CC por BU (ver Template Anexo)\n\n**5.5 Análise de variação e alertas**\n1. Comparar com mês anterior: variação > 20% em qualquer BU → investigar causa\n2. Verificar BUs com margem líquida abaixo de 20%: acionar alerta para Ruy\n3. Verificar BUs com receita zero ou negativa no mês: investigar com líder da BU\n4. Identificar top 3 projetos por margem (aprender e replicar) e bottom 3 (endereçar)\n\n**5.6 Report para diretoria (até dia 17 do mês)**\n1. Preparar resumo executivo com: margem por BU, variação vs mês anterior, alertas, próximas ações\n2. Apresentar em reunião de diretoria ou enviar via TBO OS > Financeiro > Reports\n3. Documentar decisões tomadas (ajuste de pricing, realocação de equipe, encerramento de projeto deficitário)\n\n### 6. Checklist de Validação\n- [ ] 100% das despesas do mês tagueadas com CC no OMIE\n- [ ] 100% das receitas do mês alocadas com CC no OMIE\n- [ ] Relatório de CC do OMIE extraído para o período correto (ciclo 15-15)\n- [ ] Painel de CC por BU preenchido com: receita, custos diretos, custos indiretos, margem\n- [ ] BUs com margem < 20% identificadas e comunicadas ao Ruy\n- [ ] Variações > 20% vs mês anterior investigadas\n- [ ] Report entregue para diretoria até dia 17\n- [ ] Decisões da diretoria documentadas no TBO OS\n\n### 7. Ferramentas e Recursos\n- **ERP**: OMIE — módulo Financeiro > Centros de Custo\n- **Relatórios**: OMIE > Relatórios > DRE por Centro de Custo\n- **Consolidação**: Google Sheets (template TBO — Painel CC por BU) ou TBO OS > Financeiro\n- **Histórico**: TBO OS > Financeiro > Reports > Centro de Custo\n- **Referência de equipe por BU**: MEMORY.md do TBO OS ("Equipe por BU")\n\n### 8. SLAs e Métricas\n- **Tagueamento em dia**: 100% das movimentações tagueadas em ≤ 48h após lançamento\n- **Fechamento mensal**: concluído até dia 15 do mês (ciclo 15-15)\n- **Report para diretoria**: entregue até dia 17\n- **Margem mínima por BU**: 20% de margem líquida (abaixo = alerta)\n- **Margem target por BU**: 35-45% (benchmark de agências premium)\n- **Cobertura de tagueamento**: 100% das despesas e receitas com CC\n\n### 9. Troubleshooting\n\n**Despesa sem BU clara (ex: aluguel, internet)**\n→ Alocar 100% no CC ADM com descrição clara\n→ No fechamento mensal: ADM distribui para as BUs por headcount proporcional\n→ Fórmula de rateio: (headcount BU / total headcount) × despesa compartilhada\n\n**Projeto multi-BU sem rateio definido na proposta**\n→ Acionar Atendimento + Comercial para recuperar proposta original\n→ Se não encontrado: rateio por horas estimadas de cada BU (verificar cronograma do projeto)\n→ Documentar decisão de rateio no TBO OS para auditoria futura\n\n**OMIE não exporta relatório por CC no período correto**\n→ Verificar se todos os lançamentos têm data dentro do período (data de competência, não de pagamento)\n→ Usar relatório de "Fluxo de Caixa por CC" como alternativa\n→ Se problema persistir: contatar suporte OMIE (suporte@omie.com.br)\n\n**BU com margem negativa no mês**\n→ Identificar se é pontual (projeto de alto custo/baixa receita) ou recorrente (problema estrutural)\n→ Se pontual: documentar e monitorar próximo mês\n→ Se recorrente (≥ 2 meses): apresentar análise para diretoria com proposta de solução\n→ Ações possíveis: revisão de pricing, redução de custos, reposicionamento comercial da BU\n\n### 10. Template Anexo\n\n**Template: Painel de CC por BU — Fechamento Mensal**\n\n```\nPAINEL DE CENTRO DE CUSTO POR BU\nPERÍODO: [15/MM/AAAA] a [14/MM/AAAA]\nFECHAMENTO REALIZADO POR: ___________  DATA: ___________\n\n## RESUMO POR BU\n\n| BU | Receita Bruta | Custos Diretos | Custos Indiretos | Margem Bruta | Margem Líquida | % Margem Liq. |\n|----|---------------|----------------|------------------|--------------|----------------|---------------|\n| BRD | R$ | R$ | R$ | R$ | R$ | % |\n| D3D | R$ | R$ | R$ | R$ | R$ | % |\n| MKT | R$ | R$ | R$ | R$ | R$ | % |\n| AV  | R$ | R$ | R$ | R$ | R$ | % |\n| INT | R$ | R$ | R$ | R$ | R$ | % |\n| ADM | R$ | R$ | R$ | R$ | R$ | % |\n| CORP | R$ | R$ | R$ | R$ | R$ | % |\n| **TOTAL** | **R$** | **R$** | **R$** | **R$** | **R$** | **%** |\n\n## ALERTAS\n[ ] BUs com margem líquida < 20%: ___________\n[ ] Variações > 20% vs mês anterior: ___________\n[ ] BUs sem receita no mês: ___________\n\n## VARIAÇÃO VS MÊS ANTERIOR\n| BU | Receita Atual | Receita Anterior | Variação % |\n|----|---------------|-----------------|-------------|\n| BRD | | | |\n| D3D | | | |\n...\n\n## PROJETOS DE MAIOR MARGEM (TOP 3)\n1. [Projeto | BU | Receita | Margem % | Por que foi bom]\n2.\n3.\n\n## PROJETOS DE MENOR MARGEM (BOTTOM 3)\n1. [Projeto | BU | Receita | Margem % | Causa | Ação]\n2.\n3.\n\n## DECISÕES DA DIRETORIA\n- [Decisão 1 | Responsável | Prazo]\n- [Decisão 2 | Responsável | Prazo]\n```',
    '<h2>Controle de Centro de Custo por BU</h2><p>Processo de alocação e rastreamento de custos e receitas por Business Unit da TBO para visibilidade de margem e tomada de decisão estratégica.</p>',
    'published',
    'critical',
    ARRAY['financeiro', 'centro-de-custo', 'bu', 'margem', 'dre', 'omie', 'rentabilidade', 'controle-financeiro', 'rateio', 'gestao']::TEXT[],
    0,
    1
  ) ON CONFLICT (tenant_id, slug) DO UPDATE SET
    title = EXCLUDED.title,
    content = EXCLUDED.content,
    status = EXCLUDED.status,
    updated_at = NOW();

  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-fin-008-controle-centro-custo-por-bu';

  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index)
  SELECT v_sop_id, s.step_number, s.title, s.content, s.step_type, s.order_index
  FROM (VALUES
    (1, 'Objetivo', 'Garantir visibilidade financeira por BU da TBO, permitindo que a diretoria tome decisões baseadas em dados reais de margem e rentabilidade por área. O controle de CC é a base para precificação correta, identificação de BUs deficitárias e alocação inteligente de investimentos.', 'step', 0),
    (2, 'Escopo', E'**Quem executa:** Líder Financeiro + Ruy (validação estratégica)\n**Quando se aplica:** Mensalmente, fechamento no dia 15 (ciclo 15-15)\n**BUs:** BRD (Celso/Nelson) | D3D (Eduarda/Mariane/Lucio) | MKT (Lucca/Rafa/Gustavo/M&N) | AV | INT | ADM | CORP (Marco/Ruy)', 'step', 1),
    (3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Cadastro de CC no OMIE | Líder Financeiro | Ruy | — | Marco |\n| Tagueamento de despesas | Líder Financeiro | Ruy | Líderes de BU | — |\n| Tagueamento de receitas | Líder Financeiro | Ruy | Atendimento | — |\n| Reconciliação mensal | Líder Financeiro | Ruy | Líderes de BU | Marco |\n| Análise de margem | Ruy | Marco | Líder Financeiro | — |\n| Report para diretoria | Líder Financeiro | Ruy | — | Marco |', 'step', 2),
    (4, 'Pré-requisitos', E'- CCs cadastrados no OMIE com nomenclatura padronizada (BRD, D3D, MKT, AV, INT, ADM, CORP)\n- Acesso ao OMIE com permissão de lançamento e relatórios\n- Lista de projetos ativos por BU (do TBO OS)\n- Folha de pagamento do mês fechada com equipe alocada por BU', 'step', 3),
    (5, 'Procedimento', E'**Estrutura de CCs:** Despesas de pessoal → CC da BU do colaborador. Despesas operacionais → CC da BU que usa. Despesas compartilhadas (aluguel, internet) → rateio por headcount, ADM absorve o restante. Receitas → CC da BU executora (rateio por proposta se multi-BU).\n\n**Durante o mês (contínuo):** Taguear cada despesa e receita no OMIE com o CC correspondente em ≤ 48h do lançamento. Freelancers → CC da BU contratante. Multi-BU → rateio conforme proposta.\n\n**Fechamento mensal (dia 12-15):** Extrair relatório de CC do OMIE (período 15-15). Verificar 100% de cobertura. Calcular por BU: Receita Bruta, Custos Diretos, Custos Indiretos (rateio ADM), Margem Bruta, Margem Líquida.\n\n**Análise:** Variação > 20% vs mês anterior → investigar. Margem líquida < 20% → alerta para Ruy.\n\n**Report para diretoria (até dia 17):** Resumo executivo, alertas, decisões documentadas no TBO OS.', 'step', 4),
    (6, 'Checklist de Validação', E'- [ ] 100% das despesas tagueadas com CC no OMIE\n- [ ] 100% das receitas alocadas com CC no OMIE\n- [ ] Relatório de CC extraído do período correto (ciclo 15-15)\n- [ ] Painel de CC preenchido com receita, custos e margem por BU\n- [ ] BUs com margem < 20% identificadas e comunicadas ao Ruy\n- [ ] Variações > 20% investigadas\n- [ ] Report entregue até dia 17\n- [ ] Decisões da diretoria documentadas no TBO OS', 'checkpoint', 5),
    (7, 'Ferramentas e Recursos', E'- **ERP**: OMIE > Financeiro > Centros de Custo\n- **Relatórios**: OMIE > Relatórios > DRE por Centro de Custo\n- **Consolidação**: Google Sheets (template Painel CC por BU) ou TBO OS > Financeiro\n- **Referência equipe por BU**: MEMORY.md do TBO OS', 'tip', 6),
    (8, 'SLAs e Métricas', E'- **Tagueamento**: 100% das movimentações em ≤ 48h\n- **Fechamento mensal**: até dia 15 do mês (ciclo 15-15)\n- **Report diretoria**: até dia 17\n- **Margem mínima**: 20% líquida por BU (abaixo = alerta)\n- **Margem target**: 35-45% (benchmark agências premium)\n- **Cobertura**: 100% despesas e receitas com CC', 'note', 7),
    (9, 'Troubleshooting', E'**Despesa sem BU clara:** Alocar no CC ADM. No fechamento: rateio por headcount proporcional.\n\n**Projeto multi-BU sem rateio na proposta:** Acionar Atendimento para recuperar proposta. Se não encontrado: rateio por horas estimadas de cada BU.\n\n**OMIE não exporta relatório por CC:** Verificar se lançamentos usam data de competência. Usar "Fluxo de Caixa por CC" como alternativa.\n\n**BU com margem negativa:** Se pontual → documentar e monitorar. Se recorrente (≥ 2 meses) → análise para diretoria: revisão de pricing, redução de custos ou reposicionamento.', 'warning', 8),
    (10, 'Template Anexo', 'Template de Painel de CC por BU disponível no content principal — inclui tabela completa por BU (receita, custos diretos e indiretos, margens), seção de alertas, variação vs mês anterior, ranking de projetos e registro de decisões da diretoria.', 'tip', 9)
  ) AS s(step_number, title, content, step_type, order_index)
  ON CONFLICT DO NOTHING;

-- ══════════════════════════════════════════════════════════════════════════════
-- SOP 4: Comercial — Gestão de CRM e Higiene de Pipeline
-- slug: tbo-com-008-gestao-crm-higiene-pipeline
-- ══════════════════════════════════════════════════════════════════════════════

  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Gestão de CRM e Higiene de Pipeline Comercial',
    'tbo-com-008-gestao-crm-higiene-pipeline',
    'comercial',
    'processo',
    'Processo de manutenção, atualização e higienização do pipeline comercial no CRM nativo do TBO OS — garantindo que o funil reflita a realidade, dados estejam atualizados, deals sem movimento sejam endereçados e o forecast seja confiável para tomada de decisão da diretoria',
    E'## Gestão de CRM e Higiene de Pipeline Comercial\n\n### 1. Objetivo\nGarantir que o CRM nativo do TBO OS (tabelas crm_deals, crm_deal_activities, crm_stages) reflita a realidade do pipeline comercial em tempo real. Um CRM sujo com deals desatualizados leva a forecasts errados, oportunidades perdidas e decisões estratégicas equivocadas. A higiene de CRM é um ritual semanal não-negociável.\n\n### 2. Escopo\n**Quem executa:** Ruy (Diretor Comercial) + equipe comercial\n**Quando se aplica:** Ritual semanal (toda segunda-feira) + manutenção contínua após cada interação\n**Sistema**: CRM nativo no TBO OS (não RD Station — migrado para Supabase em 2026-03-20)\n**Estágios do pipeline:** Prospecção → Qualificado → Proposta Enviada → Negociação → Fechado Ganho / Fechado Perdido\n**Exclusões:** Gestão de contratos pós-fechamento — coberta pelo SOP tbo-com-003; onboarding do cliente — coberta pelo SOP tbo-com-005\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Atualização de deal após interação | Equipe Comercial | Ruy | — | — |\n| Revisão semanal de higiene | Ruy | Marco | Equipe Comercial | — |\n| Reclassificação de deals parados | Ruy | Marco | Equipe Comercial | Atendimento |\n| Análise de forecast mensal | Ruy | Marco | Líder Financeiro | — |\n| Encerramento de deals perdidos | Ruy | Marco | Equipe Comercial | Atendimento |\n| Report de pipeline para diretoria | Ruy | Marco | — | Líder Financeiro |\n\n### 4. Pré-requisitos\n- Acesso ao TBO OS > Comercial > Pipeline (role: founder, diretoria ou lider)\n- Todos os deals da semana anterior registrados no CRM\n- Lista de follow-ups pendentes (gerada pelo CRM a partir de last_contact_at)\n- Calendário da semana com reuniões e calls comerciais agendados\n\n### 5. Procedimento\n\n**5.1 Atualização contínua após cada interação (não-negociável)**\nApós TODA interação com prospect/cliente: reunião, call, e-mail, proposta → atualizar o deal em até 2h:\n1. Registrar atividade em crm_deal_activities: tipo (call/meeting/email/proposal), data, resumo, próximo passo\n2. Atualizar campo "próxima ação" e "data de follow-up"\n3. Se houve avanço de estágio: mover o deal para o próximo estágio no pipeline kanban\n4. Se houve objeção: registrar na atividade com tipo "objeção" e categoria\n5. Atualizar valor do deal se houve negociação de preço\n\n**5.2 Ritual de higiene semanal (toda segunda-feira, 9h, ≤ 30 min)**\n\n*Passo 1 — Deals sem movimento (parados ≥ X dias por estágio):*\n- Prospecção sem atividade ≥ 7 dias: verificar → tentar recontato ou arquivar\n- Qualificado sem atividade ≥ 10 dias: verificar urgência → reengajar ou mover para perdido\n- Proposta Enviada sem resposta ≥ 5 dias: follow-up imediato\n- Negociação sem avanço ≥ 7 dias: investigar obstrução\n\n*Passo 2 — Deals com data de fechamento vencida:*\n- Verificar deals com expected_close_date no passado\n- Atualizar para nova data realista ou mover para perdido com motivo\n\n*Passo 3 — Verificar completude dos dados obrigatórios:*\nTodo deal ativo deve ter: nome do deal, empresa, contato responsável, valor estimado, estágio atual, data prevista de fechamento, responsável (owner)\n- Deals com campos faltando: preencher ou sinalizar para equipe\n\n*Passo 4 — Qualidade das atividades registradas:*\n- Verificar se último registro de atividade tem "próximo passo" claro\n- Deals com atividade mas sem próximo passo definido → atualizar agora\n\n*Passo 5 — Verificar deals "Fechado Ganho" sem onboarding iniciado:*\n- Se deal foi ganho ≥ 3 dias atrás e Atendimento ainda não foi notificado: acionar SOP tbo-com-005\n\n**5.3 Reclassificação e limpeza mensal (primeira segunda-feira do mês)**\nAlém do ritual semanal:\n1. Revisar todos os deals em "Prospecção" com > 30 dias sem movimento → arquivar ou criar campanha de reengajamento\n2. Revisar todos os deals "Perdidos" dos últimos 90 dias → classificar motivo de perda (preço, timing, concorrente, falta de budget, outro)\n3. Calcular taxa de conversão por estágio: quantos deals entram em cada estágio vs quantos avançam\n4. Identificar gargalos: qual estágio tem maior abandono?\n\n**5.4 Análise de forecast semanal**\n1. Filtrar deals em "Proposta Enviada" + "Negociação" com expected_close_date nos próximos 30 dias\n2. Aplicar ponderação por probabilidade:\n   - Proposta Enviada: × 30% de probabilidade\n   - Negociação: × 70% de probabilidade\n3. Calcular forecast ponderado: soma (valor × probabilidade)\n4. Comparar com meta mensal e calcular gap\n5. Se gap > 20% da meta: acionar plano de aceleração comercial\n\n**5.5 Report para diretoria (semanal, quinta-feira)**\n1. Extrair snapshot do pipeline do TBO OS\n2. Preparar resumo: total de deals ativos, valor total no pipeline, forecast ponderado, deals avançados na semana, deals perdidos na semana, métricas de atividade (calls, reuniões, propostas)\n3. Enviar para Marco via TBO OS > Comercial > Reports ou Slack\n\n### 6. Checklist de Validação\n- [ ] Todos os deals atualizados em ≤ 2h após cada interação\n- [ ] Ritual semanal executado toda segunda-feira (≤ 30 min)\n- [ ] Zero deals com expected_close_date vencida sem atualização\n- [ ] 100% dos deals ativos com campos obrigatórios preenchidos\n- [ ] Deals "Proposta Enviada" sem resposta ≥ 5 dias com follow-up ativo\n- [ ] Deals perdidos com motivo de perda registrado\n- [ ] Forecast ponderado calculado semanalmente\n- [ ] Report de pipeline enviado para Marco toda quinta-feira\n\n### 7. Ferramentas e Recursos\n- **CRM**: TBO OS > Comercial > Pipeline (crm_deals + crm_deal_activities)\n- **Automações**: TBO OS envia alertas automáticos para deals parados (via Supabase realtime)\n- **Comunicação**: Slack #comercial para atualizações urgentes\n- **Referência**: SOPs relacionados — tbo-com-001 (prospecção), tbo-com-002 (proposta), tbo-com-003 (fechamento), tbo-com-005 (onboarding)\n\n### 8. SLAs e Métricas\n- **Atualização pós-interação**: ≤ 2h\n- **Ritual semanal**: toda segunda-feira, ≤ 30 min\n- **Deals sem movimento**: máx. 7 dias em Prospecção, 10 dias em Qualificado, 5 dias em Proposta\n- **Cobertura de dados obrigatórios**: 100% dos deals ativos\n- **Taxa de conversão target**: Prospecção→Qualificado ≥ 40%, Qualificado→Proposta ≥ 60%, Proposta→Fechado ≥ 25%\n- **Forecast accuracy**: desvio máx. ±15% entre forecast e resultado real no fechamento do mês\n\n### 9. Troubleshooting\n\n**Equipe não atualiza o CRM após interações**\n→ Implantar regra: nenhum pagamento de comissão/bônus sem atividade registrada no CRM\n→ Usar TBO OS > Notificações para lembrete automático após reuniões agendadas\n→ Líder comercial (Ruy) revisa CRM diariamente e aciona membros omissos diretamente\n→ Se padrão persistir: endereçar na 1:1 mensal com critério de performance\n\n**Deal grande parado por burocracia interna do cliente**\n→ Registrar atividade tipo "bloqueio externo" com descrição do obstáculo\n→ Definir data de recontato específica (não "em breve")\n→ Manter no pipeline com flag "aguardando" — não mover para perdido prematuramente\n→ Escalar para Marco ou Ruy se travar por ≥ 30 dias sem perspectiva de desbloqueio\n\n**Dados históricos incompletos no CRM migrado (pré-migração RD Station)**\n→ Não investir tempo retroativo em deals fechados antes de 2026-03-20\n→ Para deals abertos que vieram do RD Station: preencher campos obrigatórios no próximo contato\n→ Dados históricos do RD Station disponíveis para consulta no Supabase (tabelas legadas)\n\n**Forecast muito acima do resultado real (otimismo no pipeline)**\n→ Revisar critérios de qualificação — usar metodologia BANT (Budget, Authority, Need, Timing)\n→ Se probabilidade de fechamento foi superestimada: recalibrar por estágio com base em dados históricos\n→ Escalar para análise com Marco se desvio > 30% por 2 meses consecutivos\n\n### 10. Template Anexo\n\n**Template: Checklist de Ritual Semanal de CRM (toda segunda-feira)**\n\n```\nRITUAL DE CRM — SEMANA [DD/MM a DD/MM/AAAA]\nResponsável: Ruy Lima  |  Duração máx: 30 minutos\n\n## 1. DEALS SEM MOVIMENTO\n[ ] Prospecção ≥ 7 dias sem atividade: ___ deals → ações: ___________\n[ ] Qualificado ≥ 10 dias sem atividade: ___ deals → ações: ___________\n[ ] Proposta Enviada ≥ 5 dias sem resposta: ___ deals → follow-ups enviados\n[ ] Negociação ≥ 7 dias sem avanço: ___ deals → obstáculo: ___________\n\n## 2. DATAS VENCIDAS\n[ ] Deals com expected_close_date no passado: ___ deals → atualizados para: ___________\n\n## 3. DADOS OBRIGATÓRIOS\n[ ] Deals sem valor estimado: ___ → preenchidos\n[ ] Deals sem responsável: ___ → atribuídos\n[ ] Deals sem data de fechamento: ___ → definidas\n\n## 4. FORECAST DA SEMANA\nProposta Enviada: R$ ___ × 30% = R$ ___\nNegociação: R$ ___ × 70% = R$ ___\n**Forecast ponderado total: R$ ___**\nMeta do mês: R$ ___  |  Realizado até agora: R$ ___  |  Gap: R$ ___\n\n## 5. MOVIMENTOS DA SEMANA\nDeals avançados de estágio: ___\nDeals ganhos: ___  (R$ ___)\nDeals perdidos: ___  (R$ ___)  |  Motivos: ___________\nNovos deals criados: ___\n\n## 6. PRÓXIMAS AÇÕES DA SEMANA\n1. [Deal | Ação | Data | Responsável]\n2.\n3.\n```\n\n**Critérios de Qualificação BANT (para atividades de qualificação)**\n```\nBUDGET (Orçamento)\n[ ] Cliente tem budget aprovado para este projeto?\n[ ] Valor estimado está dentro do range da TBO?\n\nAUTHORITY (Autoridade)\n[ ] Estamos falando com o decisor ou influenciador?\n[ ] Quem aprova a contratação?\n\nNEED (Necessidade)\n[ ] O problema/necessidade está claramente articulado?\n[ ] Existe urgência real ou é exploratório?\n\nTIMING (Prazo)\n[ ] Há um prazo definido para decidir?\n[ ] Alinha com a capacidade de entrega da TBO?\n\nPontuação: 4/4 = Deal quente (avançar). 2-3/4 = Qualificado (nutrir). 0-1/4 = Desqualificar\n```',
    '<h2>Gestão de CRM e Higiene de Pipeline Comercial</h2><p>Ritual semanal e processo contínuo de manutenção do pipeline no CRM nativo do TBO OS para forecast confiável e máxima taxa de conversão.</p>',
    'published',
    'high',
    ARRAY['comercial', 'crm', 'pipeline', 'forecast', 'higiene', 'deals', 'vendas', 'bant', 'qualificacao', 'tbo-os', 'supabase']::TEXT[],
    0,
    1
  ) ON CONFLICT (tenant_id, slug) DO UPDATE SET
    title = EXCLUDED.title,
    content = EXCLUDED.content,
    status = EXCLUDED.status,
    updated_at = NOW();

  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-com-008-gestao-crm-higiene-pipeline';

  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index)
  SELECT v_sop_id, s.step_number, s.title, s.content, s.step_type, s.order_index
  FROM (VALUES
    (1, 'Objetivo', 'Garantir que o CRM nativo do TBO OS reflita a realidade do pipeline em tempo real. Um CRM sujo leva a forecasts errados, oportunidades perdidas e decisões estratégicas equivocadas. A higiene de CRM é um ritual semanal não-negociável para Ruy e a equipe comercial.', 'step', 0),
    (2, 'Escopo', E'**Quem executa:** Ruy (Dir. Comercial) + equipe comercial\n**Quando se aplica:** Ritual semanal (toda segunda-feira) + atualização contínua após cada interação\n**Sistema:** CRM nativo no TBO OS (migrado do RD Station em 2026-03-20)\n**Estágios:** Prospecção → Qualificado → Proposta Enviada → Negociação → Fechado Ganho/Perdido', 'step', 1),
    (3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Atualização pós-interação | Equipe Comercial | Ruy | — | — |\n| Revisão semanal de higiene | Ruy | Marco | Equipe Comercial | — |\n| Reclassificação de deals parados | Ruy | Marco | Equipe Comercial | Atendimento |\n| Análise de forecast | Ruy | Marco | Líder Financeiro | — |\n| Report para diretoria | Ruy | Marco | — | Líder Financeiro |', 'step', 2),
    (4, 'Pré-requisitos', E'- Acesso ao TBO OS > Comercial > Pipeline\n- Todos os deals da semana anterior registrados no CRM\n- Lista de follow-ups pendentes gerada pelo CRM (last_contact_at)\n- Calendário da semana com reuniões e calls comerciais agendados', 'step', 3),
    (5, 'Procedimento', E'**Atualização contínua (após cada interação, ≤ 2h):**\n1. Registrar atividade (call/meeting/email/proposal), data, resumo, próximo passo\n2. Atualizar "próxima ação" e "data de follow-up"\n3. Mover estágio se houve avanço\n4. Atualizar valor se houve negociação de preço\n\n**Ritual semanal (segunda-feira, 9h, ≤ 30 min):**\n1. Deals sem movimento por estágio: Prospecção ≥ 7d, Qualificado ≥ 10d, Proposta ≥ 5d, Negociação ≥ 7d\n2. Deals com expected_close_date vencida → atualizar ou mover para perdido\n3. Verificar campos obrigatórios: nome, empresa, contato, valor, estágio, data fechamento, responsável\n4. Verificar qualidade das atividades: próximo passo claro em todos os deals ativos\n5. Deals ganhos ≥ 3 dias sem onboarding iniciado → acionar tbo-com-005\n\n**Limpeza mensal (1ª segunda-feira do mês):** Arquivar prospecções > 30d sem movimento. Classificar motivos de perda dos deals perdidos. Calcular taxa de conversão por estágio.\n\n**Forecast semanal:** Proposta × 30% + Negociação × 70% = Forecast ponderado. Comparar com meta e calcular gap.', 'step', 4),
    (6, 'Checklist de Validação', E'- [ ] Todos os deals atualizados ≤ 2h após cada interação\n- [ ] Ritual semanal executado toda segunda-feira\n- [ ] Zero deals com expected_close_date vencida sem atualização\n- [ ] 100% dos deals ativos com campos obrigatórios preenchidos\n- [ ] Deals com proposta sem resposta ≥ 5 dias com follow-up ativo\n- [ ] Deals perdidos com motivo de perda registrado\n- [ ] Forecast ponderado calculado semanalmente\n- [ ] Report enviado para Marco toda quinta-feira', 'checkpoint', 5),
    (7, 'Ferramentas e Recursos', E'- **CRM**: TBO OS > Comercial > Pipeline (crm_deals + crm_deal_activities)\n- **Alertas automáticos**: TBO OS via Supabase Realtime para deals parados\n- **Comunicação**: Slack #comercial\n- **SOPs relacionados**: tbo-com-001 (prospecção), tbo-com-002 (proposta), tbo-com-003 (fechamento)', 'tip', 6),
    (8, 'SLAs e Métricas', E'- **Atualização pós-interação**: ≤ 2h\n- **Ritual semanal**: toda segunda-feira, ≤ 30 min\n- **Deals sem movimento**: máx. 7d (Prospecção), 10d (Qualificado), 5d (Proposta)\n- **Cobertura de dados**: 100% dos deals ativos com campos obrigatórios\n- **Conversão target**: Prospecção→Qualificado ≥ 40% | Proposta→Fechado ≥ 25%\n- **Forecast accuracy**: desvio máx. ±15%', 'note', 7),
    (9, 'Troubleshooting', E'**Equipe não atualiza o CRM:** Vincular comissão/bônus ao registro de atividades. TBO OS envia lembrete após reuniões agendadas. Endereçar na 1:1 se persistir.\n\n**Deal grande parado por burocracia do cliente:** Registrar como "bloqueio externo", definir data de recontato específica. Não mover para perdido prematuramente. Escalar para Marco/Ruy se > 30 dias.\n\n**Dados históricos incompletos (pré-migração RD Station):** Não retroagir em deals fechados. Para deals abertos: preencher no próximo contato.\n\n**Forecast superestimado:** Revisar critérios BANT. Recalibrar probabilidade por estágio com dados históricos. Escalar para análise se desvio > 30% por 2 meses.', 'warning', 8),
    (10, 'Template Anexo', 'Template completo de Checklist de Ritual Semanal de CRM (com seções: deals sem movimento, datas vencidas, dados obrigatórios, forecast ponderado, movimentos da semana e próximas ações) e Critérios de Qualificação BANT disponíveis no content principal em formato copy-paste ready.', 'tip', 9)
  ) AS s(step_number, title, content, step_type, order_index)
  ON CONFLICT DO NOTHING;

END $$;
